120	/// present for the uniform subcommand-layer signature.
121	pub fn validate_desc(
122	    _ctx: &Context,
123	    params: &ValidateDescParams,
124	) -> Result<(), Box<dyn std::error::Error>> {
125	    debug!("validate-desc: enter");
126	    let (workspace, repo) = common::load_repo(&params.repo)?;
127	
128	    // Resolve other repo: --other-repo flag, or fall back to .vc-config.toml
129	    let other_repo_path = if let Some(ref p) = params.other_repo {
130	        p.clone()
131	    } else {
132	        let config = toml_simple::toml_load(&params.repo.join(VC_CONFIG_FILE))?;
133	        params.repo.join(other_repo_from_config(&config)?)
134	    };
135	
136	    let (other_workspace, other_repo) = common::load_repo(&other_repo_path)?;
137	    let other_config = toml_simple::toml_load(&other_repo_path.join(VC_CONFIG_FILE))?;
138	    let other_prefix = ochid_prefix_from_config(&other_config)?;
139	
140	    let spec = common::resolve_spec(
141	        params.pos_rev.as_deref(),
142	        params.pos_count,
143	        &params.revision,
144	        params.limit,
145	        "@",
146	    );
147	
148	    let (ids, _anchor_index) = common::collect_ids(
149	        &workspace,
150	        &repo,
151	        &spec.rev,
152	        spec.desc_count,
153	        spec.anc_count,
154	    )?;
155	    if ids.is_empty() {
156	        return Err(format!("no commits found for revision '{}'", params.revision).into());
157	    }
158	
159	    let root_id = repo.store().root_commit_id().clone();
160	    let mut valid = 0;
161	    let mut lost = 0;
162	    let mut none = 0;
163	    let mut issues_count = 0;
164	    let mut missing = 0;
165	
166	    let col_header = "STAT CHANGEID      TITLE";
167	    info!("{col_header}");
168	
169	    for commit_id in &ids {
170	        if *commit_id == root_id {
171	            continue;
172	        }
173	        let commit = repo.store().get_commit(commit_id)?;
174	        let desc = commit.description();
175	        let change_hex = jj_lib::hex_util::encode_reverse_hex(commit.change_id().as_bytes());
176	        let change_short = &change_hex[..change_hex.len().min(12)];
177	        let first_line = desc.lines().next().unwrap_or(""); // OK: obvious
178	        let display_title = if first_line.is_empty() {
179	            "(no description set)"
180	        } else {
181	            first_line
182	        };
183	
184	        let current_ochid = common::extract_ochid(&commit);
185	
186	        let status = if let Some(ref ochid_val) = current_ochid {
187	            let bare = extract_bare_id(ochid_val);
188	            if bare == "lost" {
189	                CommitStatus::Lost
190	            } else if bare == "none" {
191	                CommitStatus::None_
192	            } else {
193	                let issues = validate_ochid(
194	                    ochid_val,
195	                    &other_prefix,
196	                    params.id_len,
197	                    &other_workspace,
198	                    &other_repo,
199	                );
200	                if issues.any() {
201	                    CommitStatus::NeedsFixed(issues.summary())
202	                } else {
203	                    CommitStatus::Ok
204	                }
205	            }
206	        } else {
207	            match find_matching_commit(&commit, &other_workspace, &other_repo)? {
208	                TitleMatch::NoTitle => CommitStatus::MissingNoTitle,
209	                TitleMatch::One(id) => {
210	                    let short_id = &id[..id.len().min(params.id_len)];
211	                    CommitStatus::MissingWithMatch(format!("{other_prefix}{short_id}"))
212	                }
213	                TitleMatch::Ambiguous(n) => CommitStatus::MissingAmbiguous(n),
214	                TitleMatch::None => CommitStatus::MissingNoMatch,
215	            }
216	        };
217	
218	        match status {
219	            CommitStatus::Ok => {
220	                valid += 1;
221	                info!("ok   {change_short}  {display_title}");
222	            }
223	            CommitStatus::Lost => {
224	                lost += 1;
225	                info!("lost {change_short}  {display_title}");
226	            }
227	            CommitStatus::None_ => {
228	                none += 1;
229	                info!("none {change_short}  {display_title}");
230	            }
231	            CommitStatus::NeedsFixed(summary) => {
232	                issues_count += 1;
233	                info!("err  {change_short}  {display_title}  [{summary}]");
234	            }
235	            CommitStatus::MissingWithMatch(ochid) => {
236	                missing += 1;
237	                info!("miss {change_short}  {display_title}  [match: {ochid}]");
238	            }
239	            CommitStatus::MissingNoTitle => {
240	                missing += 1;
241	                info!("miss {change_short}  {display_title}");
242	            }
243	            CommitStatus::MissingAmbiguous(n) => {
244	                missing += 1;
245	                info!("miss {change_short}  {display_title}  [{n} title matches, ambiguous]");
246	            }
247	            CommitStatus::MissingNoMatch => {
248	                missing += 1;
249	                info!("miss {change_short}  {display_title}  [no matching title in other repo]");
250	            }
251	        }
252	    }
253	
254	    let total = valid + lost + none + issues_count + missing;
255	    if total > 10 {
256	        info!("{col_header}");
257	    }
258	    info!("");
259	    info!(
260	        "{valid} valid, {lost} lost, {none} none, {issues_count} issues, {missing} missing (of {} total)",
261	        ids.len()
262	    );
263	    if issues_count > 0 {
264	        debug!("validate-desc: exit with issues");
265	        Err(format!("{issues_count} commit(s) have issues").into())
266	    } else {
267	        debug!("validate-desc: exit");
268	        Ok(())
269	    }
270	}
