220	/// Permanent sanity check for the `main`-bookmark tracking state
221	/// in both repos of the dual-repo workspace. Emits one line on
222	/// entry and one on exit of every command. If entry and exit
223	/// differ, the executing command is the culprit; if entry differs
224	/// from the previous command's exit, something *between*
225	/// invocations broke it. Originally added in 0.37.2 as a temporary
226	/// diagnostic; promoted to permanent in 0.37.4 after the user
227	/// reported "happens more than once".
228	///
229	/// Emits at `log::debug!` (since 0.52.0-1) — default runs stay
230	/// quiet, and the signal remains available under `-v` when
231	/// investigating. The detached `finalize --exec` child runs at
232	/// default verbosity so it stays silent without needing a special
233	/// gate at the call site.
234	///
235	/// Walks up from cwd to locate the workspace root (the directory
236	/// whose `.vc-config.toml` has `path = "/"`), then probes `<root>`
237	/// and `<root>/.claude`. Same labeling whether the user runs from
238	/// the app root, from `.claude`, or from any subdir.
239	pub fn bm_track(phase: &str, command_name: &str) {
240	    let header = format!("bm-track {phase} vc-x1 {command_name}");
241	    let root = match common::find_workspace_root() {
242	        Some(r) => r,
243	        None => {
244	            log::debug!("{header}: no-workspace");
245	            return;
246	        }
247	    };
248	    let repos: [(std::path::PathBuf, &str); 2] =
249	        [(root.clone(), "app"), (root.join(".claude"), ".claude")];
250	    let mut parts: Vec<String> = Vec::new();
251	    for (repo, label) in repos {
252	        if !repo.join(".jj").exists() {
253	            parts.push(format!("{label}(main)=no-jj"));
254	            continue;
255	        }
256	        match bm_track_one(&repo, "main", "origin") {
257	            Ok(true) => parts.push(format!("{label}(main)=tracked")),
258	            Ok(false) => parts.push(format!("{label}(main)=NOT_TRACKED")),
259	            Err(e) => parts.push(format!(
260	                "{label}(main)=err({})",
261	                e.lines().next().unwrap_or("")
262	            )),
263	        }
264	    }
265	    log::debug!("{header}: {}", parts.join(", "));
266	}
267	
268	/// Query jj for whether `bookmark` in `repo` is tracking `remote`.
269	/// Returns `Ok(true)` if the tracked-list entry for `bookmark` shows
270	/// an `@<remote>` line (in any form — `@origin:` when synced, or
271	/// `@origin (ahead by N commits):` / similar when divergent — both
272	/// still count as tracking). `Ok(false)` when no such line exists
273	/// (bookmark isn't tracking this remote or doesn't exist). `Err` on
274	/// subprocess failure.
275	fn bm_track_one(repo: &Path, bookmark: &str, remote: &str) -> Result<bool, String> {
276	    let repo_str = repo.to_string_lossy();
277	    let output = std::process::Command::new("jj")
278	        .args(["bookmark", "list", "--tracked", bookmark, "-R", &repo_str])
279	        .output()
280	        .map_err(|e| format!("spawn: {e}"))?;
281	    if !output.status.success() {
282	        return Err(String::from_utf8_lossy(&output.stderr).trim().to_string());
283	    }
284	    let stdout = String::from_utf8_lossy(&output.stdout);
285	    // Accept both the synced form (`@origin:`) and the decorated
286	    // divergent form (`@origin (ahead by N commits):`), which still
287	    // represents a tracking relationship.
288	    let colon = format!("@{remote}:");
289	    let paren = format!("@{remote} ");
290	    Ok(stdout.lines().any(|l| {
291	        let t = l.trim_start();
292	        t.starts_with(&colon) || t.starts_with(&paren)
293	    }))
294	}
295	
296	fn main() -> ExitCode {
297	    CompleteEnv::with_factory(cli_with_banner).complete();
298	    let matches = cli_with_banner().get_matches();
299	    let cli = match Cli::from_arg_matches(&matches) {
300	        Ok(cli) => cli,
301	        Err(e) => {
302	            e.exit();
303	        }
304	    };
305	
306	    let log_path = cli.log.as_ref().map(|p| p.to_string_lossy().to_string());
307	    logging::CliLogger::init(cli.verbose, log_path.as_deref());
308	
309	    // `-V` / `--version`: emit the `vc-x1 X.Y.Z` banner as the
310	    // first line and continue. With no subcommand, the banner is
311	    // the whole invocation. Uniform `BANNER` (not the
312	    // `vc-x1-<sub>` form clap's `propagate_version` would print)
313	    // — the version is the binary's regardless of which
314	    // subcommand it routes to.
315	    if cli.version {
316	        log::info!("{BANNER}");
317	    }
318	
319	    let Some(cmd) = cli.command else {
320	        // No subcommand. If `-V` was set the banner has already
321	        // printed, so exit success; otherwise mirror clap's "a
322	        // subcommand is required" error by printing usage and
323	        // exiting non-zero.
324	        if cli.version {
325	            return ExitCode::SUCCESS;
326	        }
327	        let mut cmd = cli_with_banner();
328	        let _ = cmd.print_help();
329	        return ExitCode::FAILURE;
330	    };
331	
332	    // Surface any failure markers left by previous detached
333	    // `finalize --exec` children before running the next command.
334	    // Skip when this *is* the exec child — surfacing destroys the
335	    // markers, and the child's log isn't where the user looks for
336	    // them. This gate covers one race (detached child eating its
337	    // own prior markers); the broader surfacing model has more
338	    // gaps (stale-forever, concurrent double-print, mid-write torn
339	    // read, no notify-at-failure) tracked at
340	    // [../notes/todo.md#bugs] — see the
341	    // `finalize::surface_previous_failures is racy` entry.
342	    match &cmd {
343	        Commands::Finalize(args) => {
344	            if !args.exec {
345	                finalize::surface_previous_failures();
346	            }
347	        }
348	        _ => finalize::surface_previous_failures(),
349	    }
350	
351	    let ctx = match context::Context::load(cli.log) {
352	        Ok(c) => c,
353	        Err(e) => {
354	            error!("{e}");
355	            return ExitCode::FAILURE;
356	        }
357	    };
358	
359	    match cmd {
360	        Commands::Chid(args) => args.dispatch(&ctx),
361	        Commands::Desc(args) => args.dispatch(&ctx),
362	        Commands::List(args) => args.dispatch(&ctx),
363	        Commands::Show(args) => args.dispatch(&ctx),
364	        Commands::ValidateDesc(args) => args.dispatch(&ctx),
365	        Commands::FixDesc(args) => args.dispatch(&ctx),
366	        Commands::Clone(args) => args.dispatch(&ctx),
367	        Commands::Init(args) => args.dispatch(&ctx),
368	        Commands::Symlink(args) => args.dispatch(&ctx),
369	        Commands::Sync(args) => args.dispatch(&ctx),
370	        Commands::Finalize(args) => args.dispatch(&ctx),
371	        Commands::Push(args) => args.dispatch(&ctx),
372	    }
373	}
