1	//! Shared core for the `validate-todo` / `fix-todo` subcommands:
2	//! parse `notes/todo.md`'s numbered sections and compute the
3	//! renumber / re-indent plan.
4	//!
5	//! - `## Todo` and `## Bugs` hold manually-numbered entries
6	//!   (`1.` `2.` … at column 0); every other section is skipped.
7	//! - `analyze` walks the file once and returns one `Change` per
8	//!   entry whose number or continuation indent is off.
9	//! - Continuation indent is normalized against each entry's
10	//!   *measured* base indent, so nested `- ` sub-bullets keep
11	//!   their relative depth.
12	
13	/// Default todo file, relative to the workspace root.
14	pub const TODO_FILE: &str = "notes/todo.md";
15	
16	/// A manually-numbered section of the todo file.
17	#[derive(Clone, Copy, PartialEq, Eq, Debug)]
18	pub enum Section {
19	    /// The `## Todo` backlog list.
20	    Todo,
21	    /// The `## Bugs` list.
22	    Bugs,
23	}
24	
25	impl Section {
26	    /// The section's markdown header text (`## Todo` / `## Bugs`).
27	    pub fn header(self) -> &'static str {
28	        match self {
29	            Section::Todo => "## Todo",
30	            Section::Bugs => "## Bugs",
31	        }
32	    }
33	}
34	
35	/// One entry whose number and/or continuation indent needs to
36	/// change for the section to be sequentially numbered.
37	///
38	/// - `num_old` / `num_new` — the displayed number and its
39	///   sequential (1-based) position; equal when only the indent is
40	///   off.
41	/// - `indent_old` / `indent_new` — the measured continuation-base
42	///   indent and the expected one (the number prefix's width);
43	///   both `None` when the entry has no continuation lines.
44	pub struct Change {
45	    pub section: Section,
46	    pub line_no: usize,
47	    pub first_line: String,
48	    pub num_old: usize,
49	    pub num_new: usize,
50	    pub indent_old: Option<usize>,
51	    pub indent_new: Option<usize>,
52	}
53	
54	/// Result of scanning a todo file: per-section entry counts and
55	/// the list of entries needing a fix.
56	pub struct Analysis {
57	    pub todo_count: usize,
58	    pub bugs_count: usize,
59	    pub changes: Vec<Change>,
60	}
61	
62	/// An entry being accumulated during the `analyze` walk — its
63	/// first line plus the indents of its continuation lines.
64	struct PendingEntry {
65	    section: Section,
66	    line_no: usize,
67	    first_line: String,
68	    num_old: usize,
69	    num_new: usize,
70	    cont_indents: Vec<usize>,
71	}
72	
73	/// Number of decimal digits in `n` (entry numbers are ≥ 1).
74	fn digit_count(n: usize) -> usize {
75	    n.to_string().len()
76	}
77	
78	/// Classify a line as a `## ` section header.
79	///
80	/// - `None` — not a level-2 header (covers `# `, `### `, body
81	///   text).
82	/// - `Some(None)` — a `## ` header that isn't `## Todo` /
83	///   `## Bugs` (e.g. `## In Progress`, `## Done`).
84	/// - `Some(Some(section))` — the `## Todo` or `## Bugs` header.
