168	        // entry's continuation block without changing the section.
169	        if line.starts_with('#') {
170	            if let Some(p) = pending.take() {
171	                finish_entry(p, &mut changes);
172	            }
173	            continue;
174	        }
175	        let Some(sec) = section else {
