pub enum Section {
    /// The `## Todo` backlog list.
    Todo,
    /// The `## Bugs` list.
    Bugs,
}

impl Section {
    /// The section's markdown header text (`## Todo` / `## Bugs`).
    pub fn header(self) -> &'static str {
        match self {
            Section::Todo => "## Todo",
            Section::Bugs => "## Bugs",
        }
    }
}

