2	//! parse `notes/todo.md`'s numbered sections and compute the
3	//! renumber / re-indent plan.
4	//!
5	//! - `## Todo` and `## Bugs` hold manually-numbered entries
6	//!   (`1.` `2.` … at column 0); every other section is skipped.
7	//! - `analyze` walks the file once: it returns one `Change` per
8	//!   entry whose number or continuation indent is off, plus the
9	//!   fully renumbered / re-indented file content.
10	//! - Continuation indent is normalized against each entry's
11	//!   *measured* base indent, so nested `- ` sub-bullets keep
12	//!   their relative depth.
13	
14	/// Default todo file, relative to the workspace root.
15	pub const TODO_FILE: &str = "notes/todo.md";
16	
17	/// A manually-numbered section of the todo file.
18	#[derive(Clone, Copy, PartialEq, Eq, Debug)]
19	pub enum Section {
20	    /// The `## Todo` backlog list.
21	    Todo,
22	    /// The `## Bugs` list.
23	    Bugs,
24	}
25	
26	impl Section {
27	    /// The section's markdown header text (`## Todo` / `## Bugs`).
28	    pub fn header(self) -> &'static str {
29	        match self {
30	            Section::Todo => "## Todo",
31	            Section::Bugs => "## Bugs",
32	        }
33	    }
34	}
35	
36	/// One entry whose number and/or continuation indent needs to
37	/// change for the section to be sequentially numbered.
38	///
39	/// - `num_old` / `num_new` — the displayed number and its
40	///   sequential (1-based) position; equal when only the indent is
41	///   off.
42	/// - `first_line` / `new_first_line` — the entry's first line as
43	///   written and with the corrected number.
44	/// - `indent_old` / `indent_new` — the measured continuation-base
45	///   indent and the expected one (the number prefix's width);
46	///   both `None` when the entry has no continuation lines.
47	pub struct Change {
48	    pub section: Section,
49	    pub line_no: usize,
50	    pub first_line: String,
51	    pub new_first_line: String,
52	    pub num_old: usize,
53	    pub num_new: usize,
54	    pub indent_old: Option<usize>,
55	    pub indent_new: Option<usize>,
56	}
57	
58	/// Result of scanning a todo file: per-section entry counts, the
59	/// entries needing a fix, and the fully corrected file content.
60	pub struct Analysis {
61	    pub todo_count: usize,
62	    pub bugs_count: usize,
63	    pub changes: Vec<Change>,
64	    pub fixed: String,
65	}
66	
67	/// An entry being accumulated during the `analyze` walk — its
68	/// first line, that line minus its `N. ` prefix, and the raw
69	/// continuation lines (blank lines included).
70	struct PendingEntry {
71	    section: Section,
72	    line_no: usize,
73	    num_old: usize,
74	    num_new: usize,
75	    first_line: String,
76	    rest: String,
77	    cont: Vec<String>,
78	}
79	
80	/// Number of decimal digits in `n` (entry numbers are ≥ 1).
81	fn digit_count(n: usize) -> usize {
82	    n.to_string().len()
83	}
84	
85	/// Count of leading ASCII spaces on `line`.
86	fn leading_spaces(line: &str) -> usize {
87	    line.len() - line.trim_start_matches(' ').len()
88	}
89	
90	/// Classify a line as a `## ` section header.
91	///
92	/// - `None` — not a level-2 header (covers `# `, `### `, body
93	///   text).
94	/// - `Some(None)` — a `## ` header that isn't `## Todo` /
95	///   `## Bugs` (e.g. `## In Progress`, `## Done`).
96	/// - `Some(Some(section))` — the `## Todo` or `## Bugs` header.
97	fn section_header(line: &str) -> Option<Option<Section>> {
98	    if !line.starts_with("## ") {
99	        return None;
100	    }
101	    Some(match line.trim_end() {
102	        "## Todo" => Some(Section::Todo),
103	        "## Bugs" => Some(Section::Bugs),
104	        _ => None,
105	    })
106	}
107	
108	/// Parse a leading `N. ` entry prefix at column 0.
109	///
110	/// Returns `(number, prefix_len)` — the entry number and the byte
111	/// length of the `N. ` prefix — when `line` begins with one or
112	/// more ASCII digits followed by `". "` (the renumber
113	/// convention's `^\d+\. ` anchor). Returns `None` for intro lines
114	/// (which carry a leading space), continuation lines, and
115	/// headings.
116	fn parse_entry_prefix(line: &str) -> Option<(usize, usize)> {
117	    let bytes = line.as_bytes();
118	    let mut i = 0;
119	    while i < bytes.len() && bytes[i].is_ascii_digit() {
120	        i += 1;
121	    }
122	    if i == 0 || bytes.get(i) != Some(&b'.') || bytes.get(i + 1) != Some(&b' ') {
123	        return None;
124	    }
125	    let num: usize = line[..i].parse().ok()?;
126	    Some((num, i + 2))
127	}
128	
129	/// Finalize a pending entry: emit its corrected lines into `out`
130	/// and, when the number or continuation indent changed, push a
131	/// `Change`.
132	///
133	/// The continuation block is shifted as a whole by
134	/// `prefix_width − measured_base`, so a deliberately nested
135	/// sub-bullet keeps its depth relative to the entry's base.
136	fn finish_entry(p: PendingEntry, changes: &mut Vec<Change>, out: &mut Vec<String>) {
137	    let prefix_width = digit_count(p.num_new) + 2; // ". " is two chars
138	    let new_first_line = format!("{}. {}", p.num_new, p.rest);
139	
140	    // Measured base = minimum indent of the non-blank continuation
141	    // lines; `None` when the entry has no continuation text.
142	    let base = p
143	        .cont
144	        .iter()
145	        .filter(|l| !l.trim().is_empty())
146	        .map(|l| leading_spaces(l))
147	        .min();
148	    let (indent_old, indent_new) = match base {
149	        Some(b) => (Some(b), Some(prefix_width)),
150	        None => (None, None),
151	    };
152	
153	    out.push(new_first_line.clone());
154	    let delta: isize = base.map_or(0, |b| prefix_width as isize - b as isize);
155	    for line in &p.cont {
156	        if line.trim().is_empty() {
