165	        }
166	    }
167	
168	    if p.num_old != p.num_new || indent_old != indent_new {
169	        changes.push(Change {
170	            section: p.section,
171	            line_no: p.line_no,
172	            first_line: p.first_line,
173	            new_first_line,
174	            num_old: p.num_old,
175	            num_new: p.num_new,
176	            indent_old,
177	            indent_new,
178	        });
179	    }
180	}
181	
