mod tests {
    use super::*;

    /// Build a `Change` for tag tests.
    fn change(num_old: usize, num_new: usize, indent: Option<(usize, usize)>) -> Change {
        Change {
            section: Section::Todo,
            line_no: 1,
            first_line: String::new(),
            new_first_line: String::new(),
            num_old,
            num_new,
            indent_old: indent.map(|(o, _)| o),
            indent_new: indent.map(|(_, n)| n),
        }
    }

    /// A pure renumber tags only the old number.
    #[test]
    fn tag_number_only() {
        assert_eq!(change_tag(&change(3, 1, None)), "[was 3]");
    }

    /// A pure re-indent tags only the indent shift.
    #[test]
    fn tag_indent_only() {
        assert_eq!(change_tag(&change(1, 1, Some((2, 3)))), "[indent 2 → 3]");
    }

    /// A renumber that also shifts indent tags both.
    #[test]
    fn tag_number_and_indent() {
        assert_eq!(
            change_tag(&change(10, 9, Some((4, 3)))),
            "[was 10, indent 4 → 3]"
        );
    }
}

