/// Build the `[…]` tag describing what changed for an entry —
/// `[was N]`, `[indent A → B]`, or both.
fn change_tag(c: &Change) -> String {
    let mut parts: Vec<String> = Vec::new();
    if c.num_old != c.num_new {
