    fn change(num_old: usize, num_new: usize, indent: Option<(usize, usize)>) -> Change {
        Change {
            section: Section::Todo,
            line_no: 1,
            first_line: String::new(),
            new_first_line: String::new(),
            num_old,
            num_new,
