        assert_eq!(change_tag(&change(1, 1, Some((2, 3)))), "[indent 2 → 3]");
    }

    /// A renumber that also shifts indent tags both.
    #[test]
    fn tag_number_and_indent() {
        assert_eq!(
            change_tag(&change(10, 9, Some((4, 3)))),
            "[was 10, indent 4 → 3]"
        );
    }
}

